// WhatsApp Webhook Message Parser

const rawData = $input.first().json;
const payload = rawData.body || rawData;

const hubMode = payload.hub?.mode || rawData.query?.['hub.mode'] || rawData.params?.hub?.mode || '';
const hubToken = payload.hub?.['verify_token'] || rawData.query?.['hub.verify_token'] || rawData.params?.hub?.['verify_token'] || '';
const hubChallenge = payload.hub?.challenge || rawData.query?.['hub.challenge'] || rawData.params?.hub?.challenge || '';

if (hubMode === 'subscribe') {
  const expectedToken = $env.WHATSAPP_VERIFY_TOKEN || '';
  const verified = hubToken === expectedToken;
  return [{ json: { isVerification: true, verified, challenge: verified ? hubChallenge : 'Verification failed - token mismatch' } }];
}

if (payload.entry && Array.isArray(payload.entry) && payload.entry.length > 0) {
  const entry = payload.entry[0];
  if (entry.changes && Array.isArray(entry.changes) && entry.changes.length > 0) {
    const change = entry.changes[0];
    const value = change.value || {};
    if (!value.messages || !Array.isArray(value.messages) || value.messages.length === 0) {
      return [{ json: { isStatusUpdate: true } }];
    }
    const msg = value.messages[0];
    const contact = value.contacts?.[0] || null;
    const messageType = msg.type || 'text';
    let messageBody = '';
    let mediaId = '';
    if (messageType === 'text' && msg.text) messageBody = msg.text.body || '';
    else if (messageType === 'image' && msg.image) { messageBody = msg.image.caption || ''; mediaId = msg.image.id || ''; }
    else if (messageType === 'document' && msg.document) { messageBody = msg.document.caption || ''; mediaId = msg.document.id || ''; }
    else if (messageType === 'audio' && msg.audio) mediaId = msg.audio.id || '';
    else if (messageType === 'video' && msg.video) mediaId = msg.video.id || '';
    return [{ json: { isVerification: false, isStatusUpdate: false, phone: msg.from || '', message_type: messageType, message_body: messageBody, media_id: mediaId, is_media: messageType !== 'text', message_id: msg.id || '', timestamp: msg.timestamp || String(Math.floor(Date.now() / 1000)), profile_name: contact?.profile?.name || '' } }];
  }
}
return [{ json: { isStatusUpdate: true } }];

// Welcome Handler
// START state: send welcome message and transition to WAIT_PHONE

const data = $input.first().json;

if (!data.session) {
  return [{ json: { ...data, replyMessage: '', action: 'noop' } }];
}

// Update session: state → WAIT_PHONE, reset retry
const session = { ...data.session };
session.state = 'WAIT_PHONE';
session.retry_count = 0;
session.updated_at = new Date().toISOString();

return [
  {
    json: {
      ...data,
      session: session,
      replyMessage: 'Bienvenido a Superlikers. Para participar en nuestra promocion, por favor indica tu numero de telefono a 10 digitos.',
      action: 'welcome'
    }
  }
];

// Límite de reintentos
const MAX_RETRIES = 3;
const retryCount = data.retry_count || 0;

if (retryCount >= MAX_RETRIES) {
  return [[], [{ 
    json: { 
      ...data, 
      state: 'ERROR',
      action: 'max_retries_exceeded',
      replyMessage: 'Has superado el número máximo de intentos. Por favor contacta a soporte para continuar.'
    } 
  }]];
}

// Phone Validator

const COUNTRY_CODE = $env.COUNTRY_CODE || '57';
const PHONE_DIGITS = parseInt($env.PHONE_DIGITS || '10', 10);
const data = $input.first().json;
const rawPhone = data.message_body || '';
const digits = rawPhone.replace(/\D/g, '');

let localPhone = digits;
if (digits.length === PHONE_DIGITS + COUNTRY_CODE.length && digits.startsWith(COUNTRY_CODE)) {
  localPhone = digits.slice(COUNTRY_CODE.length);
}

if (localPhone.length !== PHONE_DIGITS) {
  return [{ json: { ...data, valid: false, error: `El numero debe tener ${PHONE_DIGITS} digitos locales. Recibimos ${digits.length}. Intenta de nuevo.` } }];
}

const normalizedPhone = `+${COUNTRY_CODE}${localPhone}`;
return [{ json: { ...data, valid: true, phone: normalizedPhone, normalizedPhone, localPhone, rawInput: rawPhone } }];

const data = $input.first().json;
if (data.isVerification || data.isStatusUpdate) return [{ json: data }];

let session = data.session ? { ...data.session } : null;
if (!session) return [{ json: data }];

const phone = data.normalizedPhone || data.phone || session.phone || '';
const sessionKey = `session:${phone}`;
const previousState = session.state;
const statusCode = Number(data.statusCode || 0);
const body = typeof data.body === 'object' && data.body !== null ? data.body : {};
const message = String(body.message || '').toLowerCase();

function localPhone(value) {
  return String(value || '').replace(/^\+?57/, '').replace(/\D/g, '');
}

if (data.action === 'welcome') {
} else if (data.valid === false) {
  session.retry_count = (session.retry_count || 0) + 1;
} else if (data.valid === true && phone) {
  session.phone = phone;
  session.local_phone = data.localPhone || localPhone(phone);
} else if (data.action === 'name_captured') {
  session.name = data.name || '';
  session.state = 'WAIT_EMAIL';
} else if (data.action === 'email_captured') {
  session.email = data.email || '';
  session.distinct_id = data.email || '';
  session.state = 'WAIT_CONFIRMATION';
} else if (data.action === 'confirmed') {
  session.state = 'REGISTER_PARTICIPANT';
} else if (data.action === 'cancelled') {
  session.state = 'WAIT_NAME';
  session.name = ''; session.email = ''; session.distinct_id = ''; session.retry_count = 0;
} else if (data.action === 'invoice_invalid') {
  session.state = 'WAIT_TICKET';
  session.retry_count = (session.retry_count || 0) + 1;
  data.replyMessage = data.error || 'No pude leer la factura. Envia una foto mas clara del ticket.';
} else if (data.action === 'finished') {
  session.state = 'FINISHED';
} else if (statusCode === 404) {
  session.state = 'WAIT_NAME';
  session.retry_count = 0;
} else if (statusCode >= 400) {
  session.retry_count = (session.retry_count || 0) + 1;
  session.state = session.state === 'WAIT_TICKET' ? 'WAIT_TICKET' : 'ERROR';
  if (message.includes('sha1 is already taken')) {
    data.replyMessage = 'Esta foto ya fue registrada antes. Envia un ticket diferente.';
    session.state = 'WAIT_TICKET';
  } else if (message.includes('already') || message.includes('taken') || message.includes('duplic')) {
    data.replyMessage = 'Esta factura o dato ya fue registrado antes. No vamos a duplicar puntos.';
  } else {
    data.replyMessage = body.message || 'Ocurrio un problema con la API. Intenta de nuevo en unos minutos.';
  }
} else if (statusCode === 200 && body.invoice) {
  session.invoice_ref = body.invoice.ref || session.invoice_ref || '';
  session.invoice_data = body.invoice;
  session.purchase_points = Number(body.invoice.points || 0);
  session.promotion_points = Number(body.invoice.promotions_points || body.invoice.promotion_points || 0);
  session.total_points = Number(body.participant?.available_points || body.participant?.accumulated_points || session.total_points || 0);
  session.state = 'REGISTER_PURCHASE';
} else if (statusCode === 200 && body.data && (body.data.state || body.data.execution_error !== undefined)) {
  if (body.data.execution_error) {
    session.state = 'ERROR';
    data.replyMessage = 'Tu compra quedo registrada, pero la aprobacion automatica fallo. La dejamos para revision manual.';
  } else {
    session.state = 'ACCEPT_ENTRY';
  }
} else if (statusCode === 200 && (body.object || body.email || body.points !== undefined)) {
  const participant = body.object || body;
  const email = participant.email || participant.distinct_id || '';
  session.state = email ? 'WAIT_TICKET' : 'WAIT_NAME';
  session.retry_count = 0;
  session.participant_id = participant.id || participant.participant_id || '';
  session.name = participant.name || session.name || '';
  session.email = email || session.email || '';
  session.distinct_id = email || session.distinct_id || '';
  session.phone = phone || session.phone;
  session.local_phone = data.localPhone || session.local_phone || localPhone(phone);
} else if (statusCode === 200 && message.includes('participant was successfully created')) {
  session.state = 'WAIT_TICKET';
  session.retry_count = 0;
  session.distinct_id = session.email;
  session.local_phone = session.local_phone || localPhone(session.phone);
  data.replyMessage = 'Registro exitoso. Ahora envia una foto clara de tu ticket de compra.';
} else if (statusCode === 200 && (message.includes('uploaded') || message.includes('enviada') || body.image_url || body.url || body.id || body.entry_id || body.activity_id)) {
  session.entry_id = body.id || body.entry_id || body.activity_id || body.object?.id || body.data?.id || session.entry_id || '';
  session.photo_id = session.entry_id;
  session.photo_url = body.image_url || body.url || session.photo_url || '';
  session.state = 'UPLOAD_TICKET';
  session.retry_count = 0;
} else if (statusCode === 200 && body.ok === 'false') {
  session.state = 'ERROR';
  data.replyMessage = body.message || 'La API rechazo la solicitud.';
}

if (session.state !== previousState && previousState) session.retry_count = 0;
session.updated_at = new Date().toISOString();

return [{ json: { ...data, session, sessionKey } }];

// Message Builder
// Builds WhatsApp outbound payload and webhook response metadata.

const data = $input.first().json;

if (data.isVerification) {
  return [{ json: { shouldSendWhatsApp: false, webhookRespondWith: 'text', webhookResponseBody: data.challenge || 'Verification failed', to: '', type: 'none', text: { body: data.challenge || 'Verification failed' } } }];
}

if (data.isStatusUpdate) {
  return [{ json: { shouldSendWhatsApp: false, webhookRespondWith: 'text', webhookResponseBody: 'ok', to: '', type: 'none', text: { body: 'ok' } } }];
}

const phone = data.phone || data.normalizedPhone || data.session?.phone || '';
const session = data.session || {};
let replyBody = data.replyMessage || data.error || '';

if (!replyBody && session.state) {
  switch (session.state) {
    case 'WAIT_PHONE':
      replyBody = 'Por favor indica tu numero de telefono a 10 digitos.';
      break;
    case 'WAIT_NAME':
      replyBody = 'No encontramos tu registro. Por favor indicame tu nombre completo.';
      break;
    case 'WAIT_EMAIL':
      replyBody = 'Gracias. Ahora indicame tu correo electronico.';
      break;
    case 'WAIT_CONFIRMATION':
      replyBody = `Confirma que tus datos son correctos:
Nombre: ${session.name || ''}
Email: ${session.email || ''}

Responde Si o No.`;
      break;
    case 'WAIT_TICKET':
      replyBody = 'Ya tenemos tus datos. Enviame una foto clara de tu ticket de compra en formato JPEG o PNG.';
      break;
    case 'UPLOAD_TICKET':
      replyBody = 'Gracias, recibimos tu ticket. Estamos leyendo la factura con IA...';
      break;
    case 'PROCESS_INVOICE':
      replyBody = 'Estamos preparando el registro de tu compra...';
      break;
    case 'REGISTER_PURCHASE':
      replyBody = 'Compra registrada. Estamos aprobando tu participacion...';
      break;
    case 'ACCEPT_ENTRY':
      replyBody = 'Confirmando tu participacion...';
      break;
    case 'FINISHED':
      replyBody = data.replyMessage || 'Proceso completado. Gracias por participar.';
      break;
    case 'ERROR':
      replyBody = data.replyMessage || 'Ocurrio un error controlado. Por favor intenta de nuevo o contacta soporte.';
      break;
    default:
      replyBody = 'Gracias por tu mensaje. Te responderemos pronto.';
  }
}

return [{
  json: {
    ...data,
    shouldSendWhatsApp: Boolean(phone && replyBody),
    webhookRespondWith: 'json',
    webhookResponseBody: { ok: true },
    to: phone.replace(/^\+/, ''),
    type: 'text',
    text: { body: replyBody || 'Gracias por tu mensaje. Te responderemos pronto.' }
  }
}];

// Límite de reintentos
const MAX_RETRIES = 3;
const retryCount = data.retry_count || 0;

if (retryCount >= MAX_RETRIES) {
  return [[], [{ 
    json: { 
      ...data, 
      state: 'ERROR',
      action: 'max_retries_exceeded',
      replyMessage: 'Has superado el número máximo de intentos. Por favor contacta a soporte para continuar.'
    } 
  }]];
}

// Name Handler
// Captures user's name, validates, transitions to WAIT_EMAIL
// Output 0: valid name
// Output 1: invalid name

const data = $input.first().json;
const name = (data.message_body || '').trim();

// Validate: min 3 chars, only letters and spaces (incl. accents)
const validName = /^[a-zA-Z\\u00E0-\\u00FC\\u00D1\\u00F1\\s]+$/.test(name);

if (!name || name.length < 3 || !validName) {
  const session = data.session ? {...data.session} : {};
  session.retry_count = (session.retry_count || 0) + 1;
  return [
    [],
    [{
      json: {
        ...data,
        session,
        action: 'invalid_name',
        replyMessage: 'Por favor ingresa un nombre valido (minimo 3 caracteres, solo letras y espacios).'
      }
    }]
  ];
}

const session = data.session ? {...data.session} : {};
session.name = name;
session.state = 'WAIT_EMAIL';
session.retry_count = 0;

return [
  [{
    json: {
      ...data,
      session,
      name,
      action: 'name_captured',
      replyMessage: `Gracias ${name}. Ahora indicame tu correo electronico.`
    }
  }],
  []
];

// Límite de reintentos
const MAX_RETRIES = 3;
const retryCount = data.retry_count || 0;

if (retryCount >= MAX_RETRIES) {
  return [[], [{ 
    json: { 
      ...data, 
      state: 'ERROR',
      action: 'max_retries_exceeded',
      replyMessage: 'Has superado el número máximo de intentos. Por favor contacta a soporte para continuar.'
    } 
  }]];
}

// Email Validator
// Captures user's email, validates format, transitions to WAIT_CONFIRMATION
// Output 0: valid email
// Output 1: invalid email

const data = $input.first().json;
const email = (data.message_body || '').trim().toLowerCase();

const emailRegex = /^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$/;

if (!email || !emailRegex.test(email)) {
  const session = data.session ? {...data.session} : {};
  session.retry_count = (session.retry_count || 0) + 1;
  return [
    [],
    [{
      json: {
        ...data,
        session,
        action: 'invalid_email',
        replyMessage: 'El correo ingresado no es valido. Por favor ingresa un correo electronico valido (ejemplo: nombre@correo.com).'
      }
    }]
  ];
}

const session = data.session ? {...data.session} : {};
session.email = email;
session.state = 'WAIT_CONFIRMATION';
session.retry_count = 0;

return [
  [{
    json: {
      ...data,
      session,
      email,
      action: 'email_captured',
      replyMessage: `Confirma que tus datos son correctos:\\nNombre: ${session.name || ''}\\nEmail: ${email}\\n\\nResponde Si o No.`
    }
  }],
  []
];

// Confirmation Handler
// Parses user response (Sí/No) at WAIT_CONFIRMATION
// Output 0: Sí → REGISTER_PARTICIPANT
// Output 1: No → reset to WAIT_NAME
// Output 2: fallback → stay WAIT_CONFIRMATION

const data = $input.first().json;
const response = (data.message_body || '').trim().toLowerCase();

const yesVariants = ['sí', 'si', 'yes', 'dale', 'ok', 'confirmo', 'confirmar', 'correcto'];
const noVariants = ['no', 'nop', 'cancelar', 'cancel', 'cancelar registro'];

let session = data.session ? {...data.session} : {};

if (yesVariants.includes(response)) {
  session.state = 'REGISTER_PARTICIPANT';
  session.retry_count = 0;
  return [
    [{
      json: {
        ...data,
        session,
        action: 'confirmed',
        replyMessage: 'Gracias. Estamos registrando tus datos...'
      }
    }],
    [],
    []
  ];
}

if (noVariants.includes(response)) {
  session.state = 'WAIT_NAME';
  session.name = '';
  session.email = '';
  session.retry_count = 0;
  return [
    [],
    [{
      json: {
        ...data,
        session,
        action: 'cancelled',
        replyMessage: 'OK, empecemos de nuevo. Por favor indicame tu nombre completo.'
      }
    }],
    []
  ];
}

session.retry_count = (session.retry_count || 0) + 1;
return [
  [],
  [],
  [{
    json: {
      ...data,
      session,
      action: 'unclear_confirmation',
      replyMessage: `No entendi tu respuesta. Responde Si si los datos son correctos, o No para reiniciar.\\n\\nNombre: ${session.name || ''}\\nEmail: ${session.email || ''}`
    }
  }]
];

// Register Participant Response Handler

const data = $input.first().json;
const statusCode = data.statusCode || 0;
const body = data.body || {};
const errorMessage = body.message || '';

console.log('Registration Response:', JSON.stringify({ statusCode, body }, null, 2));

// Error 422: Validación fallida
if (statusCode === 422) {
  console.log('ERROR 422:', errorMessage);
  return [[], [{ 
    json: { 
      ...data, 
      action: 'registration_validation_error',
      state: 'WAIT_NAME',
      error: errorMessage,
      replyMessage: `No pudimos completar tu registro: ${errorMessage}. Por favor verifica tus datos e intenta de nuevo.`
    } 
  }]];
}

// Error de autenticación
if (statusCode === 401) {
  console.log('ERROR: API Key inválida');
  return [[], [{ 
    json: { 
      ...data, 
      action: 'api_auth_error',
      state: 'ERROR',
      replyMessage: 'Ocurrió un error de configuración. Por favor contacta al administrador.'
    } 
  }]];
}

// Errores 5xx
if (statusCode >= 500) {
  console.log('ERROR: Servidor no disponible');
  return [[], [{ 
    json: { 
      ...data, 
      action: 'server_error',
      state: 'ERROR',
      replyMessage: 'El servicio está temporalmente fuera de línea. Por favor intenta de nuevo en unos minutos.'
    } 
  }]];
}

// Success 200
if (statusCode === 200) {
  console.log('✓ Participante registrado exitosamente');

  const session = data.session || {};
  session.state = 'WAIT_TICKET';
  session.participant_id = body.id || session.email; // distinct_id es el email

  return [{ 
    json: { 
      ...data, 
      session,
      action: 'registration_success'
    } 
  }], [];
}

// Respuesta inesperada
console.log('ERROR: Respuesta inesperada del servidor');
return [[], [{ 
  json: { 
    ...data, 
    action: 'unexpected_response',
    state: 'ERROR',
    replyMessage: 'Ocurrió un error inesperado. Por favor intenta de nuevo.'
  } 
}]];

// Validar tamaño de imagen (máximo 10MB)

const MAX_SIZE_MB = 10;
const MAX_SIZE_BYTES = MAX_SIZE_MB * 1024 * 1024;

const data = $input.first().json;
const binary = $input.first().binary;

// Verificar si hay datos binarios
if (!binary || !binary.data) {
  return [[], [{ 
    json: { 
      ...data, 
      action: 'image_invalid',
      error: 'No se recibió la imagen correctamente'
    } 
  }]];
}

// Obtener tamaño del archivo
const imageData = binary.data;
const sizeBytes = imageData.data ? imageData.data.length : 0;
const sizeMB = (sizeBytes / (1024 * 1024)).toFixed(2);

console.log(`Tamaño de imagen: ${sizeMB} MB (${sizeBytes} bytes)`);

// Validar tamaño
if (sizeBytes > MAX_SIZE_BYTES) {
  return [[], [{ 
    json: { 
      ...data, 
      action: 'image_too_large',
      size_mb: sizeMB,
      max_size_mb: MAX_SIZE_MB,
      replyMessage: `La imagen es demasiado grande (${sizeMB} MB). El tamaño máximo permitido es ${MAX_SIZE_MB} MB. Por favor envía una imagen más pequeña.`
    } 
  }]];
}

// Tamaño válido
return [{ 
  json: { 
    ...data, 
    image_size_mb: sizeMB,
    image_size_bytes: sizeBytes 
  },
  binary 
}], [];

// Upload Ticket Response Handler

const data = $input.first().json;
const statusCode = data.statusCode || 0;
const body = data.body || {};
const errorMessage = body.message || '';

console.log('Upload Ticket Response:', JSON.stringify({ statusCode, body }, null, 2));

// Error 422: Imagen duplicada (Sha1 already taken)
if (statusCode === 422 && errorMessage.includes('Sha1 is already taken')) {
  console.log('ERROR: Imagen duplicada detectada');
  return [[], [{ 
    json: { 
      ...data, 
      action: 'image_duplicate',
      state: 'ERROR',
      replyMessage: '⚠️ Este ticket ya fue registrado anteriormente. No puedes enviar la misma imagen dos veces. Si crees que es un error, contacta a soporte.'
    } 
  }]];
}

// Error 422: Otros errores de validación
if (statusCode === 422) {
  console.log('ERROR 422:', errorMessage);
  return [[], [{ 
    json: { 
      ...data, 
      action: 'upload_validation_error',
      state: 'ERROR',
      error: errorMessage,
      replyMessage: `No pudimos procesar tu ticket: ${errorMessage}. Por favor intenta de nuevo o contacta a soporte.`
    } 
  }]];
}

// Error de autenticación
if (statusCode === 401) {
  console.log('ERROR: API Key inválida');
  return [[], [{ 
    json: { 
      ...data, 
      action: 'api_auth_error',
      state: 'ERROR',
      replyMessage: 'Ocurrió un error de configuración. Por favor contacta al administrador.'
    } 
  }]];
}

// Errores 5xx (servidor)
if (statusCode >= 500) {
  console.log('ERROR: Servidor no disponible');
  return [[], [{ 
    json: { 
      ...data, 
      action: 'server_error',
      state: 'ERROR',
      replyMessage: 'El servicio está temporalmente fuera de línea. Por favor intenta de nuevo en unos minutos.'
    } 
  }]];
}

// Success 200
if (statusCode === 200 && body.id) {
  console.log('✓ Ticket subido exitosamente:', body.id);

  // Guardar entry_id para usarlo en Accept Entry
  const session = data.session || {};
  session.entry_id = body.id || body.entry_id;
  session.photo_url = body.image_url || body.url || '';
  session.state = 'PROCESS_INVOICE';

  return [{ 
    json: { 
      ...data, 
      session,
      entry_id: session.entry_id,
      photo_url: session.photo_url,
      action: 'upload_success'
    } 
  }], [];
}

// Respuesta inesperada
console.log('ERROR: Respuesta inesperada del servidor');
return [[], [{ 
  json: { 
    ...data, 
    action: 'unexpected_response',
    state: 'ERROR',
    replyMessage: 'Ocurrió un error inesperado. Por favor intenta de nuevo.'
  } 
}]];

