// Límite de reintentos
const MAX_RETRIES = 3;
const retryCount = data.retry_count || 0;

if (retryCount >= MAX_RETRIES) {
  return [[], [{ 
    json: { 
      ...data, 
      state: 'ERROR',
      action: 'max_retries_exceeded',
      replyMessage: 'Has superado el número máximo de intentos. Por favor contacta a soporte para continuar.'
    } 
  }]];
}

// Invoice Validator
// Validates OpenAI Vision response for Superlikers /retail/buy.
// Output 0: valid invoice JSON
// Output 1: invalid/illegible invoice

const data = $input.first().json;
const body = data.body || {};
const choices = body.choices || [];

if (choices.length === 0) {
  return [[], [{ json: { ...data, action: 'invoice_invalid', error: 'No se pudo procesar la imagen. Intenta con una foto mas clara.' } }]];
}

let invoiceData;
try {
  const content = choices[0].message?.content || '{}';
  invoiceData = typeof content === 'string' ? JSON.parse(content) : content;
} catch (e) {
  return [[], [{ json: { ...data, action: 'invoice_invalid', error: 'La IA no devolvio JSON valido. Intenta con una foto mas clara.' } }]];
}

const products = Array.isArray(invoiceData.products) ? invoiceData.products : [];
const normalizedProducts = products
  .map((product) => ({
    ref: String(product.ref || product.name || '').trim(),
    provider: product.provider ? String(product.provider).trim() : undefined,
    line: product.line ? String(product.line).trim() : undefined,
    price: String(product.price || '').replace(/[^0-9.]/g, ''),
    quantity: String(product.quantity || '').replace(/[^0-9.]/g, '')
  }))
  .filter((product) => product.ref && product.price && product.quantity);

const confidence = Number(invoiceData.confidence_score ?? 1);
const invoiceRef = String(invoiceData.ref || invoiceData.invoice_ref || invoiceData.invoice_number || '').trim();
const legible = invoiceData.legible !== false;

if (legible && confidence >= 0.7 && invoiceRef && normalizedProducts.length > 0) {
  invoiceData.ref = invoiceRef;
  invoiceData.products = normalizedProducts;
  return [[{ json: { ...data, invoice_data: invoiceData, action: 'invoice_valid' } }], []];
}

const reason = !legible ? 'la imagen no parece una factura legible' : (!invoiceRef ? 'falta el numero de factura' : (!normalizedProducts.length ? 'faltan productos validos' : `confianza baja (${confidence})`));
return [[], [{ json: { ...data, action: 'invoice_invalid', invoice_data: invoiceData, error: 'No se pudieron verificar los datos de la factura: ' + reason + '. Intenta con una foto mas clara.' } }]];

// Register Purchase Response Handler

const data = $input.first().json;
const statusCode = data.statusCode || 0;
const body = data.body || {};
const errorMessage = body.message || '';

console.log('Purchase Response:', JSON.stringify({ statusCode, body }, null, 2));

// Error 422: Factura duplicada (ref already taken)
if (statusCode === 422 && errorMessage.includes('ref already taken')) {
  console.log('ERROR: Factura duplicada detectada');
  return [[], [{ 
    json: { 
      ...data, 
      action: 'invoice_duplicate',
      state: 'ERROR',
      replyMessage: '⚠️ Esta factura ya fue registrada anteriormente. No puedes registrar la misma compra dos veces. Si crees que es un error, contacta a soporte.'
    } 
  }]];
}

// Error 422: Datos inválidos
if (statusCode === 422) {
  console.log('ERROR 422:', errorMessage);
  return [[], [{ 
    json: { 
      ...data, 
      action: 'purchase_validation_error',
      state: 'ERROR',
      error: errorMessage,
      replyMessage: `No pudimos registrar tu compra: ${errorMessage}. Por favor contacta a soporte.`
    } 
  }]];
}

// Error 400: Productos malformados
if (statusCode === 400) {
  console.log('ERROR 400:', errorMessage);
  return [[], [{ 
    json: { 
      ...data, 
      action: 'invalid_products',
      state: 'WAIT_TICKET',
      replyMessage: 'No pudimos procesar los productos de tu factura. Por favor envía una foto más clara del ticket.'
    } 
  }]];
}

// Error de autenticación
if (statusCode === 401) {
  console.log('ERROR: API Key inválida');
  return [[], [{ 
    json: { 
      ...data, 
      action: 'api_auth_error',
      state: 'ERROR',
      replyMessage: 'Ocurrió un error de configuración. Por favor contacta al administrador.'
    } 
  }]];
}

// Errores 5xx
if (statusCode >= 500) {
  console.log('ERROR: Servidor no disponible');
  return [[], [{ 
    json: { 
      ...data, 
      action: 'server_error',
      state: 'ERROR',
      replyMessage: 'El servicio está temporalmente fuera de línea. Por favor intenta de nuevo en unos minutos.'
    } 
  }]];
}

// Success 200
if (statusCode === 200 && body.invoice) {
  console.log('✓ Compra registrada exitosamente');

  const invoice = body.invoice || {};
  const participant = body.participant || {};

  const session = data.session || {};
  session.invoice_ref = invoice.ref || session.invoice_ref || '';
  session.purchase_points = Number(invoice.points || 0);
  session.promotion_points = Number(invoice.promotions_points || 0);
  session.total_points = session.purchase_points + session.promotion_points;
  session.available_points = Number(participant.available_points || 0);
  session.accumulated_points = Number(participant.accumulated_points || 0);
  session.state = 'ACCEPT_ENTRY';

  return [{ 
    json: { 
      ...data, 
      session,
      invoice,
      participant,
      action: 'purchase_success'
    } 
  }], [];
}

// Respuesta inesperada
console.log('ERROR: Respuesta inesperada del servidor');
return [[], [{ 
  json: { 
    ...data, 
    action: 'unexpected_response',
    state: 'ERROR',
    replyMessage: 'Ocurrió un error inesperado. Por favor intenta de nuevo.'
  } 
}]];

// Accept Entry Response Handler

const data = $input.first().json;
const statusCode = data.statusCode || 0;
const body = data.body || {};

console.log('Entry Response:', JSON.stringify({ statusCode, body }, null, 2));

// Error 404: Entry no existe
if (statusCode === 404) {
  console.log('ERROR: Entry ID no encontrado');
  return [[], [{ 
    json: { 
      ...data, 
      action: 'entry_not_found',
      state: 'ERROR',
      replyMessage: 'No encontramos el registro de tu ticket. Por favor contacta a soporte.'
    } 
  }]];
}

// Error de autenticación
if (statusCode === 401) {
  console.log('ERROR: API Key inválida');
  return [[], [{ 
    json: { 
      ...data, 
      action: 'api_auth_error',
      state: 'ERROR',
      replyMessage: 'Ocurrió un error de configuración. Por favor contacta al administrador.'
    } 
  }]];
}

// Errores 5xx
if (statusCode >= 500) {
  console.log('ERROR: Servidor no disponible');
  return [[], [{ 
    json: { 
      ...data, 
      action: 'server_error',
      state: 'ERROR',
      replyMessage: 'El servicio está temporalmente fuera de línea. Tu compra está registrada, recibirás los puntos pronto.'
    } 
  }]];
}

// Success 200 PERO con execution_error
if (statusCode === 200) {
  const responseData = body.data || body;
  const executionError = responseData.execution_error || null;
  const ok = body.ok !== false && body.ok !== 'false'; // Puede ser string "false"

  if (executionError || !ok) {
    console.log('ADVERTENCIA: Entry aceptado con errores:', executionError);
    return [[], [{ 
      json: { 
        ...data, 
        action: 'entry_error',
        state: 'ERROR',
        execution_error: executionError,
        replyMessage: '⚠️ Tu compra está registrada pero está en revisión manual. Recibirás los puntos una vez que sea aprobada por el equipo.'
      } 
    }]];
  }

  // Success completo
  console.log('✓ Entry aceptado exitosamente');

  const session = data.session || {};
  session.state = 'FINISHED';

  return [{ 
    json: { 
      ...data, 
      session,
      action: 'entry_accepted'
    } 
  }], [];
}

// Respuesta inesperada
console.log('ERROR: Respuesta inesperada del servidor');
return [[], [{ 
  json: { 
    ...data, 
    action: 'unexpected_response',
    state: 'ERROR',
    replyMessage: 'Ocurrió un error inesperado. Por favor intenta de nuevo.'
  } 
}]];

// Points Builder
// Builds final FINISHED message. Points come from /retail/buy invoice response.

const data = $input.first().json;
const session = data.session ? { ...data.session } : {};
const body = data.body || {};

const accepted = body.ok === 'true' || body.ok === true || body.data?.state === 'success';
if (body.data?.execution_error || !accepted) {
  session.state = 'ERROR';
  return [{
    json: {
      ...data,
      session,
      action: 'entry_accept_failed',
      replyMessage: 'Tu compra quedo registrada, pero la aprobacion automatica quedo en revision manual. Te avisaremos cuando se apruebe.'
    }
  }];
}

const pointsAwarded = Number(session.purchase_points || session.points_awarded || 0);
const totalPoints = Number(session.total_points || 0);
session.state = 'FINISHED';
session.retry_count = 0;

const replyMessage = '🎉 ¡Listo! Tu ticket fue aprobado.\n\nPuntos ganados por esta compra: ' + pointsAwarded + '\nTotal de puntos disponibles/acumulados: ' + totalPoints + '\n\nGracias por participar en la promocion de Superlikers.';

return [{
  json: {
    ...data,
    session,
    points_awarded: pointsAwarded,
    total_points: totalPoints,
    action: 'finished',
    replyMessage
  }
}];

// Format Log Entry
// Builds a 7-field log entry object from session data for Google Sheets logging.

const data = $input.first().json;
const session = data.session || {};
const phone = session.phone || '';
const createdAt = session.created_at || new Date().toISOString();
const conversationId = phone.replace(/\D/g, '') + '_' + createdAt.replace(/[^0-9]/g, '');
const invoiceRef = session.invoice_ref || session.invoice_data?.ref || 'N/A';
const points = data.points_awarded || session.purchase_points || session.points_awarded || 0;

const logEntry = {
  conversation_id: conversationId,
  phone,
  email: session.email || session.distinct_id || '',
  invoice_ref: invoiceRef,
  points,
  status: session.state || 'UNKNOWN',
  timestamp: new Date().toISOString()
};

return [{ json: { ...data, log_entry: logEntry } }];

// Rename Binary
// Superlikers /photos expects multipart field name upload_photo.

const items = $input.all();
return items.map(item => {
  if (item.binary && item.binary.data) {
    item.binary.upload_photo = item.binary.data;
    delete item.binary.data;
  }
  return item;
});

