const data = $input.first().json;
if (data.isVerification) return [{ json: { ...data, session: null, sessionKey: null } }];
if (data.isStatusUpdate) return [{ json: { ...data, session: null, sessionKey: null } }];
const phone = data.phone;
if (!phone) return [{ json: { ...data, session: null, sessionKey: null, error: 'No phone number provided' } }];
const sessionKey = `session:${phone}`;
return [{ json: { ...data, sessionKey } }];

const merged = $input.first().json;
if (merged.isVerification || merged.isStatusUpdate || merged.sessionKey === null) {
  return [{ json: { ...merged, session: null } }];
}
const now = new Date();
const sessionKey = merged.sessionKey || '';
let session = null;
if (merged.session_key) {
  const ts = merged.updated_at || merged.created_at || now.toISOString();
  const updatedAt = new Date(ts).getTime();
  if (now.getTime() - updatedAt < 30 * 60 * 1000) {
    session = {
      phone: merged.phone || '',
      local_phone: merged.local_phone || '',
      name: merged.name || '',
      email: merged.email || '',
      distinct_id: merged.distinct_id || '',
      state: merged.state || 'START',
      participant_id: merged.participant_id || '',
      entry_id: merged.entry_id || '',
      photo_url: merged.photo_url || '',
      invoice_ref: merged.invoice_ref || '',
      invoice_data: (() => { try { return JSON.parse(merged.invoice_data || '{}'); } catch(e) { return {}; } })(),
      purchase_points: Number(merged.purchase_points || 0),
      promotion_points: Number(merged.promotion_points || 0),
      total_points: Number(merged.total_points || 0),
      retry_count: Number(merged.retry_count || 0),
      created_at: merged.created_at || now.toISOString(),
      updated_at: now.toISOString()
    };
  }
}
if (!session) {
  session = {
    phone: merged.phone || '', local_phone: '', name: '', email: '', distinct_id: '',
    state: 'START', participant_id: '', entry_id: '', photo_url: '', invoice_ref: '',
    invoice_data: {}, purchase_points: 0, promotion_points: 0, total_points: 0,
    retry_count: 0, created_at: now.toISOString(), updated_at: now.toISOString()
  };
}
return [{ json: { ...merged, session, sessionKey } }];

const d = $input.first().json;
